+package com.google.gson.internal.bind;
+
+import com.google.gson.TypeAdapter;
+
+/**
+ * A type adapter which delegates serialization to another adapter.
+ */
+public interface SerializationDelegatingTypeAdapter<T> {
+  /** Returns the adapter to which serialization is delegated. */
+  TypeAdapter<T> getSerializationDelegate();
+}
